64	
65	## 场景分析手册
66	
67	### 场景 1：Unsafe.putObject 导致的损坏
68	
69	**症状**：
70	- 对象类型突然变成不相关的类
71	- 没有 GC 发生时出现问题
72	- 可能有反射或序列化代码
73	
74	**诊断命令**：
75	```bash
76	# 搜索 Unsafe 使用
77	grep -r "Unsafe" app/src --include="*.java"
78	grep -r "getDeclaredField.*theUnsafe" --include="*.java"
79	
80	# 查找可疑的 offset 计算
81	grep -r "objectFieldOffset" --include="*.java"
82	grep -r "\.putObject\|\.putLong" --include="*.java"
83	```
84	
85	**GDB 调试**：
86	```gdb
87	# 在 Unsafe_putObject 设置断点
88	(gdb) b art::Unsafe_putObject
89	(gdb) commands
90	  print "Unsafe.putObject called"
91	  print javaObj
92	  print offset
93	  if offset == 0
94	    print "WARNING: Writing to klass field!"
95	    bt
96	  end
97	  continue
98	end
99	```
100	
101	**修复方案**：
102	```java
103	// 在 Java 层添加检查
104	public void putObjectSafe(Object obj, long offset, Object value) {
105	    if (offset < 8) {  // 对象头大小
106	        throw new IllegalArgumentException(
107	            "Cannot modify object header at offset " + offset);
108	    }
109	    unsafe.putObject(obj, offset, value);
110	}
111	```
112	
113	### 场景 2：GC 并发竞态 (b/173676071)
114	
115	**症状**：
116	- klass 指针短暂变为 null
117	- 发生在 Concurrent Copying GC 期间
118	- 多线程环境，高并发场景
119	
120	**诊断命令**：
121	```bash
122	# 启用详细 GC 日志
123	adb shell setprop dalvik.vm.extra-opts "-Xlog:gc*"
124	adb logcat -s art,dalvikvm
125	
126	# 查找 "klass pointer found to be null" 日志
127	adb logcat | grep "klass pointer"
128	```
129	
130	**代码层面验证**：
131	```cpp
132	// 在 concurrent_copying.cc:1073 附近添加日志
133	if (UNLIKELY(ref == nullptr && offset == mirror::Object::ClassOffset())) {
134	  // 记录发生时间和线程信息
135	  LOG(ERROR) << "Race condition detected at " << std::chrono::system_clock::now()
136	             << " Thread: " << Thread::Current()->GetThreadId()
137	             << " Object: " << obj;
138	  
139	  // 收集更多上下文
140	  DumpNativeStack(LOG_STREAM(ERROR), GetTid());
141	}
142	```
143	
144	**临时 workaround**（已在 ART 源码中）：
145	```cpp
146	// 重试机制
147	for (size_t i = 0; i < 1000; i++) {
148	  usleep(1000);  // 等待 1ms
149	  ref = obj->GetClass<kVerifyNone, kWithoutReadBarrier>();
150	  if (ref != nullptr) {
151	    break;  // 成功获取
152	  }
153	}
154	```
155	
156	### 场景 3：JNI 越界写入
157	
158	**症状**：
159	- 崩溃发生在调用 native 方法之后
160	- klass 指针变成随机值（不是 null）
161	- 可能伴随其他内存损坏
162	
163	**诊断步骤**：
164	
165	1. **使用 AddressSanitizer (ASan)**：
166	```bash
167	# 编译时启用 ASan
168	# 在 Android.bp 中添加
169	cc_library {
170	    name: "libnative",
171	    sanitize: {
172	        address: true,
173	        diag: {
174	            no_recover: ["all"],
175	        },
176	    },
177	}
178	
179	# 运行应用
180	adb shell ASAN_OPTIONS=halt_on_error=0:detect_leaks=0 am start <package>
181	```
182	
183	2. **检查 JNI 代码**：
184	```cpp
185	// 危险模式：直接指针操作
186	JNIEXPORT void JNICALL
187	Java_com_example_Native_dangerousWrite(JNIEnv* env, jobject obj) {
188	    // ❌ 错误：将 Java 对象当作 C 结构体
189	    uint64_t* ptr = (uint64_t*)obj;
190	    ptr[0] = 0x1234567890ABCDEF;  // 覆盖 klass!
191	}
192	
193	// 安全模式：使用 JNI API
194	JNIEXPORT void JNICALL
195	Java_com_example_Native_safeWrite(JNIEnv* env, jobject obj) {
196	    // ✅ 正确：使用 JNI 函数
197	    jclass clazz = env->GetObjectClass(obj);
198	    jfieldID fid = env->GetFieldID(clazz, "field", "I");
199	    env->SetIntField(obj, fid, 42);
200	}
201	```
202	
203	3. **添加边界检查**：
204	```cpp
205	// 在缓冲区操作中添加检查
206	void copyData(JNIEnv* env, jobject dst, jbyteArray src) {
207	    jsize len = env->GetArrayLength(src);
208	    jbyte* buf = env->GetByteArrayElements(src, nullptr);
209	    
210	    // ✅ 检查边界
211	    if (len > MAX_SAFE_SIZE) {
212	        env->ReleaseByteArrayElements(src, buf, JNI_ABORT);
213	        return;
214	    }
215	    
216	    // 安全复制
217	    memcpy(safe_buffer, buf, len);
218	    env->ReleaseByteArrayElements(src, buf, JNI_ABORT);
219	}
220	```
221	
222	### 场景 4：Mark-Compact GC 引用更新顺序问题
223	
224	**症状**：
225	- 发生在 Mark-Compact GC 之后
226	- klass 指向已移动的旧地址
227	- 访问类元数据时崩溃
228	
229	**诊断**：
230	```bash
231	# 强制触发 Mark-Compact GC
232	adb shell am force-gc <package>
233	
234	# 查看 GC 类型
235	adb logcat | grep "GC_TYPE"
236	# 查找 "mark compact" 或 "compacting"
237	```
238	
239	**代码分析**：
240	```cpp
241	// runtime/gc/collector/mark_compact.cc
242	// 检查 Class 对象是否在更新前被访问
243	
244	void MarkCompact::UpdateNonMovingSpace() {
245	  // 关键：必须按反向顺序遍历
246	  // 确保跨页对象的 class 指针最后更新
247	  
248	  // 如果正向遍历，可能出现：
249	  // 1. 对象 A 的 klass 指针已更新
250	  // 2. 但 Class 对象本身还在旧位置
251	  // 3. 读取 klass->GetComponentType() 访问旧地址 -> 崩溃
252	}
253	```
254	
255	## 预防性编程实践
256	
257	### 1. 安全的 Unsafe 封装
258	
259	```java
260	public class SafeUnsafe {
261	    private static final Unsafe UNSAFE = getUnsafe();
262	    private static final int OBJECT_HEADER_SIZE = 8;
263	    
264	    public static void putObjectSafe(Object obj, long offset, Object value) {
265	        if (offset < OBJECT_HEADER_SIZE) {
266	            throw new IllegalArgumentException(
267	                "Cannot write to object header (offset=" + offset + ")");
268	        }
269	        
270	        // 额外验证：检查 offset 是否对齐
271	        if (offset % 4 != 0) {
272	            throw new IllegalArgumentException(
273	                "Unaligned offset: " + offset);
274	        }
275	        
276	        UNSAFE.putObject(obj, offset, value);
277	    }
278	    
279	    public static void putLongSafe(Object obj, long offset, long value) {
280	        if (offset < OBJECT_HEADER_SIZE) {
281	            throw new IllegalArgumentException(
282	                "Cannot write to object header");
283	        }
284	        UNSAFE.putLong(obj, offset, value);
285	    }
286	}
287	```
288	
289	### 2. JNI 最佳实践
290	
291	```cpp
292	// ✅ 使用 RAII 管理 JNI 资源
293	class JNIStringGuard {
294	public:
295	    JNIStringGuard(JNIEnv* env, jstring str) 
296	        : env_(env), str_(str) {
297	        chars_ = env_->GetStringUTFChars(str_, nullptr);
298	    }
299	    
300	    ~JNIStringGuard() {
301	        if (chars_) {
302	            env_->ReleaseStringUTFChars(str_, chars_);
303	        }
304	    }
305	    
306	    const char* get() const { return chars_; }
307	    
308	private:
309	    JNIEnv* env_;
310	    jstring str_;
311	    const char* chars_;
312	};
313	
314	// 使用示例
315	void processString(JNIEnv* env, jstring str) {
316	    JNIStringGuard guard(env, str);
317	    // 自动清理，即使异常也安全
318	    doWork(guard.get());
319	}
320	```
321	
322	```cpp
323	// ✅ 检查 JNI 调用返回值
324	jclass clazz = env->FindClass("com/example/MyClass");
325	if (clazz == nullptr) {
326	    // 检查异常
327	    if (env->ExceptionCheck()) {
328	        env->ExceptionDescribe();
329	        env->ExceptionClear();
330	    }
331	    return;
332	}
333	
334	jfieldID fid = env->GetFieldID(clazz, "field", "I");
335	if (fid == nullptr) {
336	    LOG(ERROR) << "Field not found";
337	    return;
338	}
339	```
340	
341	### 3. 运行时断言
342	
343	```cpp
344	// 在关键路径添加验证
345	void Object::SetClass(ObjPtr<Class> new_klass) {
346	#ifdef ART_ENABLE_KLASS_VERIFICATION
347	    // 编译时可选的额外检查
348	    if (new_klass != nullptr) {
349	        DCHECK(new_klass->IsClassClass() || new_klass->IsArrayClass() ||
