374	
375	@Test
376	public void testConcurrentGCStress() {
377	    // 压力测试 GC 并发场景
378	    ExecutorService executor = Executors.newFixedThreadPool(8);
379	    AtomicInteger errors = new AtomicInteger(0);
380	    
381	    for (int i = 0; i < 1000; i++) {
382	        executor.submit(() -> {
383	            try {
384	                Object[] objects = new Object[1000];
385	                for (int j = 0; j < objects.length; j++) {
