390	                    }
391	                }
392	                System.gc();  // 触发 GC
393	            } catch (Exception e) {
394	                errors.incrementAndGet();
395	            }
396	        });
397	    }
398	    
399	    executor.shutdown();
400	    executor.awaitTermination(1, TimeUnit.MINUTES);
401	    assertEquals(0, errors.get());
402	}
403	```
404	
405	## 监控和告警
406	
407	### 1. 运行时监控
408	
409	```java
