464	    mirror::Class* klass = obj->GetClass<kVerifyNone, kWithoutReadBarrier>();
465	    if (klass == nullptr) {
466	        os << "ERROR: GetClass() returned null!\n";
467	        return;
468	    }
469	    
470	    os << "Klass address: " << klass << "\n";
471	    
472	    // 检查 klass 指针是否在有效堆区域
473	    gc::Heap* heap = Runtime::Current()->GetHeap();
474	    if (!heap->IsValidObjectAddress(klass)) {
475	        os << "ERROR: Klass points to invalid memory!\n";
476	        os << "Heap bounds: " << heap->GetContinuousSpaces() << "\n";
