## 监控和告警

### 1. 运行时监控

```java
// 定期检查堆健康状况
class HeapHealthMonitor {
    private static final ScheduledExecutorService scheduler = 
        Executors.newScheduledThreadPool(1);

    public static void startMonitoring() {
        scheduler.scheduleAtFixedRate(() -> {
            try {
                // 检查 GC 频率
                long gcCount = getGCCount();
                long gcTime = getGCTime();

                if (gcTime > 5000) {  // 5秒以上
                    Log.w("HeapMonitor", "Excessive GC time: " + gcTime + "ms");
                }

                // 采样验证对象
                sampleObjects();

            } catch (Exception e) {
                Log.e("HeapMonitor", "Monitoring failed", e);
            }
        }, 0, 30, TimeUnit.SECONDS);
    }

    private static void sampleObjects() {
        // 创建测试对象并验证
        Object testObj = new Object();
        Class<?> cls = testObj.getClass();

        if (cls == null || !cls.getName().equals("java.lang.Object")) {
            Log.e("HeapMonitor", "CRITICAL: Klass pointer corruption detected!");
            // 触发告警
            crashReport("Klass corruption");
        }
    }
}
```

### 2. Crash 报告增强

```cpp
// 在崩溃处理器中添加 klass 信息
void DumpKlassInfo(std::ostream& os, mirror::Object* obj) {
    os << "Object address: " << obj << "\n";

    uint32_t klass_ref = *reinterpret_cast<uint32_t*>(obj);
    os << "Klass reference (raw): 0x" << std::hex << klass_ref << "\n";

    if (klass_ref == 0) {
        os << "ERROR: Null klass pointer!\n";
        return;
    }

    mirror::Class* klass = obj->GetClass<kVerifyNone, kWithoutReadBarrier>();
    if (klass == nullptr) {
        os << "ERROR: GetClass() returned null!\n";
        return;
    }

    os << "Klass address: " << klass << "\n";

    // 检查 klass 指针是否在有效堆区域
    gc::Heap* heap = Runtime::Current()->GetHeap();
    if (!heap->IsValidObjectAddress(klass)) {
        os << "ERROR: Klass points to invalid memory!\n";
        os << "Heap bounds: " << heap->GetContinuousSpaces() << "\n";
        return;
    }

    os << "Klass type: " << klass->PrettyDescriptor() << "\n";
}
```

